import { Injectable, inject } from '@angular/core';
import { from, Observable, of } from 'rxjs';
import { map } from 'rxjs/operators';
import { SupabaseService } from '../../services/Base/supabase.service';
import { AuthService } from './timbrature-auth.adapter';
import { User } from '../models';

@Injectable({ providedIn: 'root' })
export class UsersService {
  private supabase = inject(SupabaseService).getSupabaseClient();
  private authService = inject(AuthService);

  // Rimappa company_id → restaurant_id tramite restaurant_staff
getByCompany(restaurantId: string, role?: string): Observable<User[]> {
  if (!restaurantId) return of([]);
  const promise = (async () => {
    // 1. Staff del ristorante (escludi social_media_manager)
    let staffQuery: any = this.supabase
      .from('restaurant_staff')
      .select('user_id, role, permissions')
      .eq('restaurant_id', restaurantId)
      .eq('invitation_status', 'accepted')
      .neq('role', 'social_media_manager');

    if (role) {
      staffQuery = staffQuery.eq('role', this.mapRole(role));
    }

    const { data: staffList, error: staffError } = await staffQuery;
    if (staffError) throw staffError;

    // 2. Proprietario del ristorante
    const { data: restaurant } = await this.supabase
      .from('restaurants')
      .select('owner_id')
      .eq('id', restaurantId)
      .maybeSingle();

    // 3. Raccogli tutti gli ID unici
    const staffUserIds = (staffList || []).map((s: any) => s.user_id).filter(Boolean);
    const allUserIds = [...new Set([
      ...staffUserIds,
      ...(restaurant?.owner_id && !role ? [restaurant.owner_id] : [])
      // owner viene incluso solo se non c'è filtro per ruolo
    ])];

    if (!allUserIds.length) return [];

    // 4. Dati utente
    const { data: users, error: usersError } = await this.supabase
      .from('users')
      .select('*')
      .in('id', allUserIds)
      .eq('is_active', true);

    if (usersError) throw usersError;

    // 5. Arricchisci con ruolo
    return (users || []).map((u: any) => {
      const staffRecord = (staffList || []).find((s: any) => s.user_id === u.id);
      const isOwner = u.id === restaurant?.owner_id;
      return {
        ...u,
        company_id: restaurantId,
        role: isOwner ? 'admin' : (staffRecord?.role || u.role),
        staff_permissions: staffRecord?.permissions || []
      };
    }) as User[];
  })();
  return from(promise);
}

  getManagers(restaurantId: string): Observable<User[]> {
    return this.getByCompany(restaurantId, 'manager');
  }

  getEmployees(restaurantId: string): Observable<User[]> {
    return this.getByCompany(restaurantId, 'employee');
  }

  findByEmail(email: string, restaurantId: string): Observable<User | null> {
    return from(
      this.supabase
        .from('users')
        .select('*')
        .eq('email', email)
        .maybeSingle()
        .then((res: any) => {
          if (res.error) throw res.error;
          return res.data as User | null;
        })
    );
  }

  setActiveStatus(userId: string, active: boolean, companyId?: string): Observable<any> {
    return from(
      this.supabase
        .from('users')
        .update({ is_active: active, updated_at: new Date().toISOString() })
        .eq('id', userId)
        .select()
        .maybeSingle()
        .then((res: any) => {
          if (res.error) throw res.error;
          return res.data;
        })
    );
  }

  softDelete(userId: string, deletedBy: string, companyId?: string): Observable<any> {
    return from(
      this.supabase
        .from('users')
        .update({ is_active: false, updated_at: new Date().toISOString() })
        .eq('id', userId)
        .select()
        .maybeSingle()
        .then((res: any) => {
          if (res.error) throw res.error;
          return res.data;
        })
    );
  }

  restore(userId: string, companyId?: string): Observable<any> {
    return from(
      this.supabase
        .from('users')
        .update({ is_active: true, updated_at: new Date().toISOString() })
        .eq('id', userId)
        .select()
        .maybeSingle()
        .then((res: any) => {
          if (res.error) throw res.error;
          return res.data;
        })
    );
  }

  getUserWithDetails(userId: string): Observable<any> {
    return from(
      this.supabase
        .from('users')
        .select('*')
        .eq('id', userId)
        .maybeSingle()
        .then((res: any) => {
          if (res.error) throw res.error;
          return res.data;
        })
    );
  }

  search(restaurantId: string, search: string): Observable<User[]> {
    const promise = (async () => {
      const { data: staffList } = await this.supabase
        .from('restaurant_staff')
        .select('user_id')
        .eq('restaurant_id', restaurantId)
        .eq('invitation_status', 'accepted');

      const userIds = (staffList || []).map((s: any) => s.user_id).filter(Boolean);
      if (!userIds.length) return [];

      const { data, error } = await this.supabase
        .from('users')
        .select('*')
        .in('id', userIds)
        .or(`first_name.ilike.%${search}%,last_name.ilike.%${search}%,email.ilike.%${search}%`)
        .limit(20);

      if (error) throw error;
      return (data || []) as User[];
    })();
    return from(promise);
  }

  updateNotificationPreferences(userId: string, preferences: any): Observable<any> {
    return from(
      this.supabase
        .from('users')
        .update({ notifications_preferences: preferences, updated_at: new Date().toISOString() })
        .eq('id', userId)
        .select()
        .maybeSingle()
        .then((res: any) => {
          if (res.error) throw res.error;
          return res.data;
        })
    );
  }

  // Mappa ruoli Timbrature → ruoli Platea
  private mapRole(role: string): string {
    const map: Record<string, string> = {
      'admin': 'manager',
      'manager': 'manager',
      'employee': 'waiter'
    };
    return map[role] || role;
  }

getById(userId: string): Observable<User | null> {
  if (!userId) return of(null);
  return from(
    this.supabase
      .from('users')
      .select('*')
      .eq('id', userId)
      .maybeSingle()
      .then((res: any) => {
        if (res.error) throw res.error;
        const data = res.data;
        if (data) data.company_id = this.authService.companyId;
        return data as User | null;
      })
  );
}

update(userId: string, patch: Partial<User>, companyId?: string): Observable<User> {
  const { company_id, ...safePatch } = patch as any;
  return from(
    this.supabase
      .from('users')
      .update({ ...safePatch, updated_at: new Date().toISOString() })
      .eq('id', userId)
      .select('*')
      .maybeSingle()
      .then((res: any) => {
        if (res.error) throw res.error;
        return { ...res.data, company_id: this.authService.companyId } as User;
      })
  );
}

getAll(restaurantId: string): Observable<User[]> {
  return this.getByCompany(restaurantId);
}
}